import os
import psutil

def close_all_running_applications():
    # Get a list of all running processes
    for process in psutil.process_iter(['pid', 'name']):
        try:
            # Skip system processes and the current script
            if process.info['name'] in ['System Idle Process', 'explorer.exe', 'python.exe']:
                continue
            # Terminate the process
            process.terminate()
            # Wait for 1 second to allow the process to terminate
            process.wait(timeout=1)
        except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.TimeoutExpired):
            pass

if __name__ == "__main__":
    close_all_running_applications()
